function solve(edges, online, k) {
    const n = online.length;
    const adj = new Map();
    for (const [u, v, cost] of edges) {
        if (!adj.has(u)) adj.set(u, []);
        adj.get(u).push(v);
    }

    const in_degree = new Array(n).fill(0);
    for (const [u, v, cost] of edges) {
        in_degree[v]++;
    }

    const queue = [];
    for (let i = 0; i < n; i++) {
        if (in_degree[i] === 0) queue.push(i);
    }

    const topological_order = [];
    while (queue.length > 0) {
        const u = queue.shift();
        topological_order.push(u);
        for (const v of adj.get(u) || []) {
            in_degree[v]--;
            if (in_degree[v] === 0) queue.push(v);
        }
    }

    let max_cost = 0;
    for (const [u, v, cost] of edges) {
        if (cost > max_cost) max_cost = cost;
    }

    let low = 0, high = max_cost;
    let answer = -1;

    function check(mid) {
        const allowed_edges = [];
        for (const [u, v, cost] of edges) {
            if (!online[u]) continue;
            if (v !== n - 1 && !online[v]) continue;
            if (cost < mid) continue;
            allowed_edges.push({ u, v, cost });
        }

        const adj_check = new Map();
        for (const { u, v, cost } of allowed_edges) {
            if (!adj_check.has(u)) adj_check.set(u, []);
            adj_check.get(u).push({ v, cost });
        }

        const dist = new Array(n).fill(Infinity);
        dist[0] = 0;

        for (const u of topological_order) {
            if (dist[u] === Infinity) continue;
            if (!online[u]) continue;
            if (adj_check.has(u)) {
                for (const { v, cost } of adj_check.get(u)) {
                    if (dist[v] > dist[u] + cost) {
                        dist[v] = dist[u] + cost;
                    }
                }
            }
        }

        return dist[n - 1] <= k;
    }

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        if (check(mid)) {
            answer = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return answer;
}
